                           <p className="text-xs text-gray-500 font-sans leading-relaxed group-hover:text-gray-400">
                             {s.description}
                           </p>
                         </Link>
                       ))}
                     </div>
                     <div className="bg-white/5 px-6 py-3 border-t border-white/5 flex justify-between items-center">
                        <span className="text-xs text-gray-400 uppercase tracking-widest">Soluciones Integrales</span>
                        <a href={waLink} target="_blank" rel="noreferrer" className="text-xs font-bold text-raynold-green hover:text-white transition-colors">COTIZAR AHORA &rarr;</a>
                     </div>
                  </motion.div>
                )}
