                 <Star size={20} />
                 {favorites.length > 0 && (
                   <span className="absolute -top-2 -right-2 w-4 h-4 bg-raynold-red text-white text-[10px] flex items-center justify-center rounded-full font-bold">
                     {favorites.length}
