                    to={`/services/${s.slug}`}
                    onClick={() => setIsOpen(false)} 
                    className="block text-gray-300 py-1 hover:text-raynold-red transition-colors cursor-pointer"
                  >
                    {s.title}
                  </Link>
                ))}
              </div>
              <Link to="/products" onClick={() => setIsOpen(false)} className="block text-lg font-bold text-white">PRODUCTOS</Link>
