const RollingNumber = ({ label }: { label: string }) => {
  const [num, setNum] = useState(0);
  useEffect(() => {
    const interval = setInterval(() => {
      setNum(Math.floor(Math.random() * 9999));
    }, 150);
    return () => clearInterval(interval);
  }, []);
  return (
    <div className="flex flex-col text-[10px] font-mono text-raynold-green/70">
      <span className="text-raynold-red/50 uppercase tracking-widest text-[8px]">{label}</span>
      <span>{num.toString().padStart(4, '0')}</span>
    </div>
  );
};

const CollisionParticle = ({ delay }: { delay: number }) => {
  // Random position for the explosion
  const top = useMemo(() => Math.random() * 80 + 10, []); // 10% to 90%
  const left = useMemo(() => Math.random() * 80 + 10, []); 

  return (
    <motion.div
      className="absolute w-2 h-2"
      style={{ top: `${top}%`, left: `${left}%` }}
      initial={{ scale: 0, opacity: 0 }}
      animate={{ 
        scale: [0, 1.5, 3], 
        opacity: [0, 1, 0],
        rotate: [0, 45, 90]
      }}
      transition={{ 
        duration: 2, 
        repeat: Infinity, 
        delay: delay,
        ease: "easeOut",
        repeatDelay: Math.random() * 3 + 1
      }}
    >
      {/* Core */}
      <div className="absolute inset-0 bg-white rounded-full blur-[1px]" />
      {/* Shockwave */}
      <div className="absolute inset-0 border border-raynold-red rounded-full scale-150" />
