import React, { useState, useEffect } from 'react';
import { motion, useScroll, useSpring, useTransform, AnimatePresence } from 'framer-motion';
import { ChevronUp, Zap } from 'lucide-react';

const ScrollDrone: React.FC = () => {
  const { scrollYProgress, scrollY } = useScroll();
  const [isHovered, setIsHovered] = useState(false);
  const [showDrone, setShowDrone] = useState(false);

  // Smooth out the scroll progress
  const scaleX = useSpring(scrollYProgress, {
    stiffness: 100,
    damping: 30,
    restDelta: 0.001
  });

  // Transform color based on scroll position (Red -> White -> Green)
  const color = useTransform(
    scrollYProgress,
    [0, 0.5, 1],
    ["#E60000", "#FFFFFF", "#009933"]
  );

  // Rotate based on scroll
  const rotate = useTransform(scrollY, [0, 5000], [0, 720]);

  // Show drone only after scrolling a bit
  useEffect(() => {
    return scrollY.on("change", (latest) => {
      setShowDrone(latest > 100);
    });
  }, [scrollY]);

  const scrollToTop = () => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <AnimatePresence>
      {showDrone && (
        <motion.div
          initial={{ opacity: 0, scale: 0, y: 100 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0, y: 100 }}
          className="fixed bottom-8 right-8 z-[90] pointer-events-auto"
        >
          <motion.div
            className="relative w-16 h-16 cursor-pointer"
            onMouseEnter={() => setIsHovered(true)}
            onMouseLeave={() => setIsHovered(false)}
            onClick={scrollToTop}
            whileHover={{ scale: 1.1 }}
            whileTap={{ scale: 0.9 }}
          >
            {/* 1. Orbiting Particles (The "Wandering" Effect) */}
            <motion.div 
              className="absolute inset-[-10px] rounded-full border border-white/10"
              animate={{ rotate: 360 }}
              transition={{ duration: 10, repeat: Infinity, ease: "linear" }}
            >
              <div className="absolute top-0 left-1/2 -translate-x-1/2 w-2 h-2 bg-raynold-red rounded-full shadow-[0_0_10px_#E60000]" />
            </motion.div>

            <motion.div 
              className="absolute inset-[-10px] rounded-full border border-white/5"
              animate={{ rotate: -360 }}
              transition={{ duration: 15, repeat: Infinity, ease: "linear" }}
            >
              <div className="absolute bottom-0 left-1/2 -translate-x-1/2 w-1.5 h-1.5 bg-raynold-green rounded-full shadow-[0_0_10px_#009933]" />
            </motion.div>

            {/* 2. Progress Ring SVG */}
            <svg className="absolute inset-0 w-full h-full -rotate-90 transform" viewBox="0 0 100 100">
              {/* Background Track */}
              <circle
                cx="50"
                cy="50"
                r="46"
                fill="black"
                stroke="rgba(255,255,255,0.1)"
                strokeWidth="4"
              />
              {/* Progress Indicator */}
              <motion.circle
                cx="50"
                cy="50"
                r="46"
                fill="transparent"
                stroke={color}
                strokeWidth="4"
                strokeLinecap="round"
                style={{ pathLength: scaleX }}
              />
            </svg>

            {/* 3. Core (The "Eye") */}
            <div className="absolute inset-2 rounded-full bg-black/80 backdrop-blur-sm flex items-center justify-center overflow-hidden border border-white/20">
              {/* Inner rotating element */}
              <motion.div 
                style={{ rotate }}
                className="absolute inset-0 flex items-center justify-center"
              >
                 <div className="w-full h-1 bg-gradient-to-r from-transparent via-white/50 to-transparent opacity-50" />
                 <div className="absolute w-1 h-full bg-gradient-to-b from-transparent via-white/50 to-transparent opacity-50" />
              </motion.div>

              {/* Icon Change on Hover */}
              <AnimatePresence mode="wait">
                {isHovered ? (
                  <motion.div
                    key="arrow"
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -10 }}
                  >
                    <ChevronUp className="text-white drop-shadow-[0_0_5px_rgba(255,255,255,0.8)]" />
                  </motion.div>
                ) : (
                  <motion.div
                    key="zap"
                    initial={{ opacity: 0, scale: 0.5 }}
                    animate={{ opacity: 1, scale: 1 }}
                    exit={{ opacity: 0, scale: 0.5 }}
                  >
                    <motion.div style={{ color }}>
                       <Zap size={20} fill="currentColor" className="drop-shadow-lg" />
                    </motion.div>
                  </motion.div>
                )}
              </AnimatePresence>
            </div>

            {/* 4. Hover Hologram Effect */}
            <AnimatePresence>
               {isHovered && (
                 <motion.div
                   initial={{ opacity: 0, scale: 0.8 }}
                   animate={{ opacity: 1, scale: 1 }}
                   exit={{ opacity: 0, scale: 0.8 }}
                   className="absolute bottom-full right-0 mb-4 px-3 py-1 bg-black/80 border border-white/20 rounded text-[10px] font-futuristic text-white whitespace-nowrap backdrop-blur-md"
                 >
                   SISTEMA ACTIVO <br/> 
                   <span className="text-raynold-green">CLICK PARA SUBIR</span>
                 </motion.div>
               )}
            </AnimatePresence>

          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

