const ScrollDrone: React.FC = () => {
  const [activeSection, setActiveSection] = useState<string>('hero');
  const [currentConfig, setCurrentConfig] = useState(sectionConfig['hero']);
  const [isHovered, setIsHovered] = useState(false);

  // Detect active section
  useEffect(() => {
    const handleScroll = () => {
      const sections = Object.keys(sectionConfig);

      // Find the section that is most visible in the viewport
      let maxVisibleSection = activeSection;
      let maxVisibility = 0;

      sections.forEach(sectionId => {
        const element = document.getElementById(sectionId);
        if (element) {
          const rect = element.getBoundingClientRect();
          const viewHeight = window.innerHeight;

          // Calculate how much of the element is visible
          const visibleHeight = Math.min(rect.bottom, viewHeight) - Math.max(rect.top, 0);
          const visibility = Math.max(0, visibleHeight / viewHeight);

          if (visibility > maxVisibility && visibility > 0.3) { // Threshold
            maxVisibility = visibility;
            maxVisibleSection = sectionId;
          }
        }
      });

      if (maxVisibleSection !== activeSection) {
        setActiveSection(maxVisibleSection);
        setCurrentConfig(sectionConfig[maxVisibleSection]);
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, [activeSection]);

  const scrollToTop = () => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <motion.div
      className="fixed z-[50] pointer-events-none"
      initial={{ x: '85vw', y: '20vh' }}
      animate={{ 
        x: currentConfig.x, 
        y: currentConfig.y 
      }}
      transition={{ 
        type: "spring", 
        stiffness: 40, // Robótico: rápido al inicio
        damping: 15,   // Freno suave
        mass: 1.2
      }}
    >
      {/* Floating Wrapper (Idle Animation) */}
      <motion.div
        animate={{ y: [0, -15, 0] }}
        transition={{ duration: 4, repeat: Infinity, ease: "easeInOut" }}
        className="relative pointer-events-auto"
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
        onClick={scrollToTop}
      >

        {/* --- DRONE BODY --- */}
        <div className="relative w-24 h-24 group cursor-pointer">

          {/* 1. Outer Rotating Shield */}
          <motion.div 
            className="absolute inset-0 rounded-full border border-white/10 border-dashed"
            animate={{ rotate: 360 }}
            transition={{ duration: 20, repeat: Infinity, ease: "linear" }}
          />

          {/* 2. Fast Scanning Ring */}
          <motion.div 
            className="absolute inset-2 rounded-full border-t border-l border-white/30"
            animate={{ rotate: -360 }}
            transition={{ duration: 3, repeat: Infinity, ease: "linear" }}
          />

          {/* 3. Core Engine */}
          <div className="absolute inset-6 rounded-full bg-black/80 backdrop-blur-md border border-white/20 shadow-[0_0_30px_rgba(0,0,0,0.5)] flex items-center justify-center overflow-hidden">

             {/* Energy Pulse */}
             <motion.div 
               className="absolute inset-0 bg-gradient-to-tr from-black via-transparent to-white/10"
               animate={{ opacity: [0.5, 0.8, 0.5] }}
               transition={{ duration: 2, repeat: Infinity }}
             />

             {/* Central Eye */}
             <motion.div 
                className="w-3 h-3 rounded-full shadow-[0_0_15px_currentColor]"
                style={{ backgroundColor: currentConfig.color, color: currentConfig.color }}
                animate={{ scale: [1, 1.5, 1] }}
                transition={{ duration: 1, repeat: Infinity }}
             />

             {/* Crosshair Overlay */}
             <div className="absolute inset-0 flex items-center justify-center opacity-30">
                <Scan size={32} className="text-white" strokeWidth={1} />
             </div>
          </div>

          {/* 4. Thrusters (Particles) */}
          <div className="absolute bottom-0 left-1/2 -translate-x-1/2 translate-y-4">
             <motion.div 
               className="w-1 h-8 blur-sm"
               style={{ backgroundColor: currentConfig.color }}
               animate={{ height: [10, 20, 10], opacity: [0.5, 0] }}
               transition={{ duration: 0.2, repeat: Infinity }}
             />
          </div>

        </div>

        {/* --- HOLOGRAPHIC MESSAGE --- */}
        <AnimatePresence mode="wait">
          <motion.div
            key={activeSection}
            initial={{ opacity: 0, x: currentConfig.align === 'left' ? 20 : -20, scale: 0.9 }}
            animate={{ opacity: 1, x: 0, scale: 1 }}
            exit={{ opacity: 0, scale: 0.9 }}
            className={`absolute top-0 ${currentConfig.align === 'left' ? 'left-full ml-4' : 'right-full mr-4'} w-48`}
          >
            <div className="relative p-3 bg-black/80 border border-white/20 rounded-lg backdrop-blur-md shadow-2xl">

              {/* Decor lines */}
              <div className="absolute top-0 left-0 w-2 h-2 border-t border-l border-white/50" />
              <div className="absolute bottom-0 right-0 w-2 h-2 border-b border-r border-white/50" />

              {/* Header */}
              <div className="flex items-center gap-2 mb-1 border-b border-white/10 pb-1">
                 <Aperture size={10} className={currentConfig.color === '#E60000' ? 'text-red-500' : 'text-green-500'} />
                 <span className="text-[9px] font-mono text-gray-400 uppercase tracking-widest">DRONE-IA v2.0</span>
              </div>

              {/* Text */}
              <p className="text-[10px] text-white font-futuristic leading-relaxed">
                {currentConfig.text}
              </p>

              {/* Connector Line to Drone */}
              <div className={`absolute top-1/2 -translate-y-1/2 w-4 h-[1px] bg-white/20 ${currentConfig.align === 'left' ? '-left-4' : '-right-4'}`}></div>
              <div className={`absolute top-1/2 -translate-y-1/2 w-1 h-1 bg-white rounded-full ${currentConfig.align === 'left' ? '-left-4' : '-right-4'}`}></div>
            </div>
          </motion.div>
        </AnimatePresence>

        {/* Hover Hint */}
        <AnimatePresence>
          {isHovered && (
            <motion.div
               initial={{ opacity: 0, y: 10 }}
               animate={{ opacity: 1, y: 0 }}
               exit={{ opacity: 0 }}
               className="absolute -bottom-8 left-1/2 -translate-x-1/2 whitespace-nowrap"
            >
               <span className="text-[9px] bg-white text-black px-2 py-0.5 rounded font-bold uppercase">
                 Click para subir
               </span>
            </motion.div>
          )}
        </AnimatePresence>

      </motion.div>
    </motion.div>
  );
};

