const App: React.FC = () => {
  // Initialize Lenis Smooth Scroll with "Slider/Pagination" feel configuration
  useEffect(() => {
    const lenis = new Lenis({
      duration: 0.8, // Reduced from 1.5 to 0.8 for lighter feel (less "heavy")
      easing: (t) => 1 - Math.pow(1 - t, 4), // Quartic ease-out for "push and brake" feel
      direction: 'vertical',
      gestureDirection: 'vertical',
      smooth: true,
      mouseMultiplier: 1.5, // Increased sensitivity so small wheel movements do more
      smoothTouch: false, // Native touch is better for mobile "snap" feel
      touchMultiplier: 2,
    });

    function raf(time: number) {
      lenis.raf(time);
      requestAnimationFrame(raf);
    }

    requestAnimationFrame(raf);

    return () => {
      lenis.destroy();
    };
  }, []);

  return (
    <HashRouter>
      <ScrollToTop />
      <div className="min-h-screen bg-raynold-black text-white selection:bg-raynold-red selection:text-white font-sans flex flex-col relative overflow-x-hidden">
