const ScrollDrone: React.FC = () => {
  const [activeSection, setActiveSection] = useState<string>('hero');
  const [currentConfig, setCurrentConfig] = useState(sectionConfig['hero']);
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });

  // Detect active section
  useEffect(() => {
    const handleScroll = () => {
      const sections = Object.keys(sectionConfig);

      let maxVisibleSection = activeSection;
      let maxVisibility = 0;

      sections.forEach(sectionId => {
        const element = document.getElementById(sectionId);
        if (element) {
          const rect = element.getBoundingClientRect();
          const viewHeight = window.innerHeight;
          const visibleHeight = Math.min(rect.bottom, viewHeight) - Math.max(rect.top, 0);
          const visibility = Math.max(0, visibleHeight / viewHeight);

          if (visibility > maxVisibility && visibility > 0.3) {
            maxVisibility = visibility;
            maxVisibleSection = sectionId;
          }
        }
      });

      if (maxVisibleSection !== activeSection) {
        setActiveSection(maxVisibleSection);
        setCurrentConfig(sectionConfig[maxVisibleSection]);
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, [activeSection]);

  // Track Mouse
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
        setMousePosition({ x: e.clientX, y: e.clientY });
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  // Calculate Repulsion Vector
  const getRepulsion = () => {
    if (typeof window === 'undefined') return { x: 0, y: 0 };

    // Convert current target config to pixels (approximate)
    const targetX = (parseFloat(currentConfig.x) * window.innerWidth) / 100;
    const targetY = (parseFloat(currentConfig.y) * window.innerHeight) / 100;

    const dx = targetX - mousePosition.x;
    const dy = targetY - mousePosition.y;
    const distance = Math.sqrt(dx * dx + dy * dy);

    const repulsionRadius = 300; // Trigger distance
    const maxRepulsion = 150;    // Max pixels to move away

    if (distance < repulsionRadius) {
        const force = Math.pow((repulsionRadius - distance) / repulsionRadius, 2); // Exponential force for smoother feel
        const angle = Math.atan2(dy, dx);
        return {
            x: Math.cos(angle) * force * maxRepulsion,
            y: Math.sin(angle) * force * maxRepulsion
        };
    }
    return { x: 0, y: 0 };
  };

  const repulsion = getRepulsion();
  const isRepelling = Math.abs(repulsion.x) > 10 || Math.abs(repulsion.y) > 10;

  return (
    <motion.div
      className="fixed z-[50] pointer-events-none"
      initial={{ x: '85vw', y: '20vh' }}
      animate={{ 
        x: `calc(${currentConfig.x} + ${repulsion.x}px)`, 
        y: `calc(${currentConfig.y} + ${repulsion.y}px)` 
      }}
      transition={{ 
        type: "spring", 
        stiffness: isRepelling ? 120 : 60, // Stiffer when evading
        damping: isRepelling ? 15 : 20,    // Less damping when evading for quick response
        mass: 1
      }}
    >
      {/* Floating Wrapper */}
      <motion.div
        animate={{ y: [0, -15, 0] }}
        transition={{ duration: 4, repeat: Infinity, ease: "easeInOut" }}
        className="relative"
      >

        {/* --- DRONE BODY --- */}
        <div className="relative w-24 h-24 group">

          {/* 1. Outer Rotating Shield */}
          <motion.div 
            className={`absolute inset-0 rounded-full border border-dashed transition-colors duration-300 ${isRepelling ? 'border-raynold-red/50' : 'border-white/10'}`}
            animate={{ rotate: 360, scale: isRepelling ? 1.1 : 1 }}
            transition={{ duration: isRepelling ? 2 : 20, repeat: Infinity, ease: "linear" }}
          />

          {/* 2. Fast Scanning Ring */}
          <motion.div 
            className="absolute inset-2 rounded-full border-t border-l border-white/30"
            animate={{ rotate: -360 }}
            transition={{ duration: 3, repeat: Infinity, ease: "linear" }}
          />

          {/* 3. Core Engine */}
          <div className={`absolute inset-6 rounded-full backdrop-blur-md border shadow-[0_0_30px_rgba(0,0,0,0.5)] flex items-center justify-center overflow-hidden transition-colors duration-300 ${isRepelling ? 'bg-red-900/40 border-red-500/50' : 'bg-black/80 border-white/20'}`}>

             {/* Energy Pulse */}
             <motion.div 
               className="absolute inset-0 bg-gradient-to-tr from-black via-transparent to-white/10"
               animate={{ opacity: [0.5, 0.8, 0.5] }}
               transition={{ duration: 2, repeat: Infinity }}
             />

             {/* Central Eye */}
             <motion.div 
                className="w-3 h-3 rounded-full shadow-[0_0_15px_currentColor]"
                style={{ backgroundColor: isRepelling ? '#ff0000' : currentConfig.color, color: isRepelling ? '#ff0000' : currentConfig.color }}
                animate={{ scale: [1, 1.5, 1] }}
                transition={{ duration: 0.5, repeat: Infinity }}
             />

             {/* Crosshair Overlay */}
             <div className="absolute inset-0 flex items-center justify-center opacity-30">
                {isRepelling ? <AlertTriangle size={32} className="text-red-500" /> : <Scan size={32} className="text-white" strokeWidth={1} />}
             </div>
          </div>

          {/* 4. Thrusters (Particles) */}
          <div className="absolute bottom-0 left-1/2 -translate-x-1/2 translate-y-4">
             <motion.div 
               className="w-1 h-8 blur-sm"
               style={{ backgroundColor: isRepelling ? '#ff0000' : currentConfig.color }}
               animate={{ height: isRepelling ? [20, 40, 20] : [10, 20, 10], opacity: [0.5, 0] }}
               transition={{ duration: 0.1, repeat: Infinity }}
             />
          </div>

        </div>

        {/* --- HOLOGRAPHIC MESSAGE --- */}
        <AnimatePresence mode="wait">
          <motion.div
            key={isRepelling ? 'warning' : activeSection}
            initial={{ opacity: 0, x: currentConfig.align === 'left' ? 20 : -20, scale: 0.9 }}
            animate={{ opacity: 1, x: 0, scale: 1 }}
            exit={{ opacity: 0, scale: 0.9 }}
            className={`absolute top-0 ${currentConfig.align === 'left' ? 'left-full ml-4' : 'right-full mr-4'} w-48`}
          >
            <div className={`relative p-3 border rounded-lg backdrop-blur-md shadow-2xl transition-colors duration-300 ${isRepelling ? 'bg-red-950/80 border-red-500/50' : 'bg-black/80 border-white/20'}`}>

              {/* Decor lines */}
              <div className="absolute top-0 left-0 w-2 h-2 border-t border-l border-white/50" />
              <div className="absolute bottom-0 right-0 w-2 h-2 border-b border-r border-white/50" />

              {/* Header */}
              <div className={`flex items-center gap-2 mb-1 border-b pb-1 ${isRepelling ? 'border-red-500/30' : 'border-white/10'}`}>
                 <Aperture size={10} className={isRepelling ? 'text-red-500' : (currentConfig.color === '#E60000' ? 'text-red-500' : 'text-green-500')} />
                 <span className={`text-[9px] font-mono uppercase tracking-widest ${isRepelling ? 'text-red-400' : 'text-gray-400'}`}>
                   {isRepelling ? 'ALERTA DE PROXIMIDAD' : 'DRONE-IA v2.0'}
                 </span>
              </div>

              {/* Text */}
              <p className={`text-[10px] font-futuristic leading-relaxed ${isRepelling ? 'text-red-200' : 'text-white'}`}>
                {isRepelling ? "DESPEJANDO ÁREA VISUAL. ACCESO PERMITIDO." : currentConfig.text}
              </p>

              {/* Connector Line to Drone */}
              <div className={`absolute top-1/2 -translate-y-1/2 w-4 h-[1px] ${isRepelling ? 'bg-red-500/50' : 'bg-white/20'} ${currentConfig.align === 'left' ? '-left-4' : '-right-4'}`}></div>
              <div className={`absolute top-1/2 -translate-y-1/2 w-1 h-1 ${isRepelling ? 'bg-red-500' : 'bg-white'} rounded-full ${currentConfig.align === 'left' ? '-left-4' : '-right-4'}`}></div>
            </div>
          </motion.div>
        </AnimatePresence>

      </motion.div>
    </motion.div>
  );
};

