const Ruler = ({ orientation = 'horizontal', side = 'bottom' }: { orientation?: 'horizontal' | 'vertical', side?: 'left' | 'right' | 'top' | 'bottom' }) => {
  const isHorizontal = orientation === 'horizontal';
  const ticks = 21;

  return (
    <div className={`absolute z-20 pointer-events-none opacity-40 hidden md:flex ${
      isHorizontal 
        ? 'w-[90%] left-[5%] h-8 border-gray-700/50 flex justify-between items-end' 
        : 'h-[70%] top-[15%] w-8 border-gray-700/50 flex flex-col justify-between items-end'
    } ${
      side === 'bottom' ? 'bottom-8 border-t' : 'left-8 border-r'
    }`}>
      {Array.from({ length: ticks }).map((_, i) => (
        <div key={i} className={`relative ${isHorizontal ? 'h-full w-px flex flex-col justify-end items-center' : 'w-full h-px flex flex-row justify-end items-center'}`}>
          {/* Main Tick */}
          <div className={`bg-white/40 ${isHorizontal ? 'w-px h-2' : 'h-px w-2'}`} />

          {/* Major Tick & Number */}
          {i % 5 === 0 && (
             <>
