import React, { useEffect } from 'react';
import gsap from 'gsap';
import ScrollTrigger from 'gsap/ScrollTrigger';
import { useLocation } from 'react-router-dom';

gsap.registerPlugin(ScrollTrigger);

const GsapController: React.FC = () => {
  const location = useLocation();

  useEffect(() => {
    // Clean up previous triggers to avoid conflicts on route change
    ScrollTrigger.getAll().forEach(t => t.kill());

    // 1. GLOBAL: Reveal Text Animation (Cyberpunk Decode Style)
    // Applies to any element with class 'gsap-reveal'
    const revealElements = document.querySelectorAll('.gsap-reveal');
    revealElements.forEach((element) => {
      gsap.fromTo(element, 
        { 
          y: 50, 
          opacity: 0, 
          scale: 0.95,
          filter: 'blur(10px)'
        },
        {
          y: 0,
          opacity: 1,
          scale: 1,
          filter: 'blur(0px)',
          duration: 1,
          ease: 'power3.out',
          scrollTrigger: {
            trigger: element,
            start: 'top 85%',
            toggleActions: 'play none none reverse'
          }
        }
      );
    });

    // 2. HERO: Parallax Background
    // Looks for 'gsap-hero-bg'
    const heroBg = document.querySelector('.gsap-hero-bg');
    if (heroBg) {
      gsap.to(heroBg, {
        yPercent: 30, // Moves down slower than scroll
        ease: 'none',
        scrollTrigger: {
          trigger: '#hero',
          start: 'top top',
          end: 'bottom top',
          scrub: true
        }
      });
    }

    // 3. PROCESS: Laser Line Drawing
    // Draws an SVG line connecting steps in the Process section
    const processSection = document.getElementById('process');
    const processLine = document.querySelector('.gsap-process-line path');

    if (processSection && processLine) {
       const length = (processLine as SVGPathElement).getTotalLength();

       // Set initial state: hidden line
       gsap.set(processLine, { 
         strokeDasharray: length, 
         strokeDashoffset: length 
       });

       gsap.to(processLine, {
         strokeDashoffset: 0,
         ease: 'none',
         scrollTrigger: {
           trigger: processSection,
           start: 'top center',
           end: 'bottom bottom',
           scrub: 1
         }
       });
    }

    // 4. HUD Progress Bar (Right Side)
    const progressBar = document.getElementById('hud-progress-bar');
    if (progressBar) {
      gsap.to(progressBar, {
        height: '100%',
        ease: 'none',
        scrollTrigger: {
          trigger: 'body',
          start: 'top top',
          end: 'bottom bottom',
          scrub: 0.3
        }
      });
    }

    // Force refresh to calculate positions correctly after DOM updates
    const timer = setTimeout(() => ScrollTrigger.refresh(), 500);
    return () => clearTimeout(timer);

  }, [location.pathname]); // Re-run on route change

  // --- HUD UI Component Rendered via Portal or directly fixed ---
  return (
    <div className="fixed right-0 top-0 h-full w-12 pointer-events-none z-40 hidden md:flex flex-col items-center justify-center mix-blend-difference">
      {/* Track */}
      <div className="h-[60%] w-[1px] bg-white/10 relative">
        {/* Fill Bar */}
        <div 
          id="hud-progress-bar" 
          className="absolute top-0 left-0 w-full bg-raynold-red shadow-[0_0_10px_#E60000]" 
          style={{ height: '0%' }}
        />

        {/* Markers */}
        <div className="absolute top-0 -left-2 text-[8px] font-mono text-gray-500">00</div>
        <div className="absolute top-1/4 -left-2 w-2 h-[1px] bg-white/20"></div>
        <div className="absolute top-2/4 -left-2 w-3 h-[1px] bg-white/40"></div>
        <div className="absolute top-3/4 -left-2 w-2 h-[1px] bg-white/20"></div>
        <div className="absolute bottom-0 -left-2 text-[8px] font-mono text-gray-500">100</div>
      </div>
    </div>
  );
};

