// --- Custom Cursor Component ---
const CustomCursor = () => {
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
  const [isHovering, setIsHovering] = useState(false);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      setMousePosition({ x: e.clientX, y: e.clientY });

      const target = e.target as HTMLElement;
      // Check if hovering over clickable elements
      const isClickable = target.closest('a, button, input, select, textarea, [role="button"]');
      setIsHovering(!!isClickable);
    };

    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  return (
    <div 
      className="fixed top-0 left-0 w-full h-full pointer-events-none z-[1000] hidden md:block mix-blend-difference"
      style={{ overflow: 'hidden' }}
    >
      <motion.div
        className="absolute rounded-full border border-white flex items-center justify-center"
        animate={{
          x: mousePosition.x - (isHovering ? 20 : 10),
          y: mousePosition.y - (isHovering ? 20 : 10),
          width: isHovering ? 40 : 20,
          height: isHovering ? 40 : 20,
          borderColor: isHovering ? '#E60000' : '#FFFFFF',
          rotate: isHovering ? 90 : 0
        }}
        transition={{ type: "tween", ease: "backOut", duration: 0.15 }}
      >
        <div className={`w-1 h-1 bg-white rounded-full ${isHovering ? 'bg-red-500' : ''}`} />

        {/* Crosshair Lines */}
        {isHovering && (
           <>
             <motion.div initial={{ width: 0 }} animate={{ width: '150%' }} className="absolute h-[1px] bg-red-500/50 top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
             <motion.div initial={{ height: 0 }} animate={{ height: '150%' }} className="absolute w-[1px] bg-red-500/50 top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
           </>
        )}
      </motion.div>
    </div>
  );
};

// --- BIOS Boot Loader Component ---
const BiosLoader = ({ onComplete }: { onComplete: () => void }) => {
  const [lines, setLines] = useState<string[]>([]);

  const bootSequence = [
    "RAYNOLD SYSTEM v5.0.1 - (c) 2025 Raynold Design SRL",
    "Initializing Neural Networks...",
    "Loading Graphic Drivers... [OK]",
    "Calibrating Color Gamut RGB... [OK]",
    "Checking Hardware Acceleration... [ENABLED]",
    "Mounting Virtual Reality Modules...",
    "Connecting to Drone Satellite Link... [CONNECTED]",
    "System Ready.",
    "EXECUTING MAIN_INTERFACE.EXE"
  ];

  useEffect(() => {
    let delay = 0;
    bootSequence.forEach((line, index) => {
      delay += Math.random() * 300 + 100;
      setTimeout(() => {
        setLines(prev => [...prev, line]);
        if (index === bootSequence.length - 1) {
          setTimeout(onComplete, 800);
        }
      }, delay);
    });
  }, []);

  return (
    <div className="fixed inset-0 bg-black z-[100] p-8 md:p-16 font-mono text-xs md:text-sm text-green-500 overflow-hidden">
      <div className="max-w-3xl mx-auto h-full flex flex-col justify-end">
        {lines.map((line, i) => (
          <div key={i} className="mb-1">
            <span className="text-gray-500 mr-2">[{new Date().toLocaleTimeString()}]</span>
            {line}
          </div>
        ))}
        <motion.div 
          animate={{ opacity: [0, 1] }} 
          transition={{ repeat: Infinity, duration: 0.5 }}
          className="w-3 h-5 bg-green-500 inline-block align-middle ml-1"
        />
      </div>
    </div>
  );
};

