    const processSection = document.getElementById('process');
    const processLine = document.querySelector('.process-path') as SVGPathElement;
    const processCards = document.querySelectorAll('.gsap-process-card');

    if (processSection && processLine && processCards.length > 0) {
       const length = processLine.getTotalLength();

       // Initialize: Line hidden, Cards hidden and moved down
       gsap.set(processLine, { strokeDasharray: length, strokeDashoffset: length });
       gsap.set(processCards, { opacity: 0, y: 50, scale: 0.9 });

       const tl = gsap.timeline({
         scrollTrigger: {
           trigger: processSection,
           start: 'top 60%', // Start animation when section is in view
           end: 'bottom 80%',
           scrub: 1.5, // Smooth scrubbing
         }
       });

       // Step 1: Draw line to first card (approx 12.5%)
       tl.to(processLine, { strokeDashoffset: length * 0.85, duration: 1, ease: "none" })
         // Reveal Card 1 & Activate
         .to(processCards[0], { opacity: 1, y: 0, scale: 1, duration: 0.5 }, "<")
         .add(() => { processCards[0].classList.add('process-card-active'); }, ">-0.2")

       // Step 2: Draw line to second card (approx 37.5%)
         .to(processLine, { strokeDashoffset: length * 0.60, duration: 1, ease: "none" })
         // Reveal Card 2 & Activate
         .to(processCards[1], { opacity: 1, y: 0, scale: 1, duration: 0.5 }, "<")
         .add(() => { processCards[1].classList.add('process-card-active'); }, ">-0.2")

