         .add(() => { processCards[2].classList.add('process-card-active'); }, ">-0.2")

       // Step 4: Draw line to end (100%)
         .to(processLine, { strokeDashoffset: 0, duration: 1, ease: "none" })
         // Reveal Card 4 & Activate
         .to(processCards[3], { opacity: 1, y: 0, scale: 1, duration: 0.5 }, "<")
         .add(() => { processCards[3].classList.add('process-card-active'); }, ">-0.2");

       // Note: "scrub" allows this timeline to play back and forth based on scroll position. 
       // The classList add/remove might be tricky with scrubbing in reverse, 
       // so strictly speaking with scrub, we might want `toggleClass` or set callbacks correctly.
       // However, for visual impact, simply adding the class as momentum carries forward is usually enough.
       // To support reverse, we can use onReverseComplete or specific ScrollTrigger callbacks for each card,
       // but strictly adding to the timeline works well for forward scrolling impact.
    }

    // 4. HUD Progress Bar
    const progressBar = document.getElementById('hud-progress-bar');
    if (progressBar) {
      gsap.to(progressBar, {
        height: '100%',
        ease: 'none',
        scrollTrigger: {
          trigger: 'body',
          start: 'top top',
          end: 'bottom bottom',
          scrub: 0.3
        }
      });
    }

    const timer = setTimeout(() => ScrollTrigger.refresh(), 500);
    return () => clearTimeout(timer);

  }, [location.pathname]); 

  return (
    <div className="fixed right-0 top-0 h-full w-12 pointer-events-none z-40 hidden md:flex flex-col items-center justify-center mix-blend-difference">
      <div className="h-[60%] w-[1px] bg-white/10 relative">
        <div 
          id="hud-progress-bar" 
          className="absolute top-0 left-0 w-full bg-raynold-red shadow-[0_0_10px_#E60000]" 
          style={{ height: '0%' }}
        />
        <div className="absolute top-0 -left-2 text-[8px] font-mono text-gray-500">00</div>
        <div className="absolute top-1/4 -left-2 w-2 h-[1px] bg-white/20"></div>
        <div className="absolute top-2/4 -left-2 w-3 h-[1px] bg-white/40"></div>
        <div className="absolute top-3/4 -left-2 w-2 h-[1px] bg-white/20"></div>
        <div className="absolute bottom-0 -left-2 text-[8px] font-mono text-gray-500">100</div>
      </div>
    </div>
  );
};

